proof:
by
  -- Define a bijection between the set of even integers and the set of natural numbers.
  have h_bij : ∃ f : {n : ℤ | even n} → ℕ, Function.Bijective f := by
    have h_bij : Nonempty ( {n : ℤ | even n} ≃ ℕ ) := by
      norm_num +zetaDelta at *;
      refine' Cardinal.eq.1 _;
      rw [ show { n : ℤ // even n } = ( Set.range fun n : ℤ => 2 * n ) from ?_ ];
      · rw [ Cardinal.mk_range_eq ] ; aesop;
        exact mul_right_injective₀ two_ne_zero;
      · congr with x ; simp +decide [ even_iff_two_dvd ] ; aesop;
    exact ⟨ _, Equiv.bijective h_bij.some ⟩;
  obtain ⟨ f, hf ⟩ := h_bij;
  obtain ⟨ g, hg ⟩ := hf;
  use Equiv.ofBijective f ⟨ g, hg ⟩ |> Equiv.symm;
  exact ⟨ Equiv.injective _, Equiv.surjective _ ⟩

